class Solution:
    def numberOfSubarrays(self, nums, k: int) -> int:
        count = 0
        for i in range(len(nums)):
            odd = 0
            for j in range(i, len(nums)):
                if nums[j] % 2 == 1:
                    odd += 1
                if odd == k:
                    count += 1
                elif odd > k:
                    break
        return count

