var numberOfSubarrays = function(nums, k) {
    const prefix = new Map([[0, 1]]);
    let odd = 0, ans = 0;
    for (const x of nums) {
        odd += x % 2;
        ans += (prefix.get(odd - k) || 0);
        prefix.set(odd, (prefix.get(odd) || 0) + 1);
    }
    return ans;
};
